import{_ as a,W as r,X as t,Y as i,Z as e,a0 as d}from"./framework-91490e6a.js";const h={},n=e("p",null,"终于毕业了，但是毕业了也就意味着分别，分别也就意味着我得搬离了，并且是跨省搬家。",-1),o=e("p",null,"那么如何跨省搬家呢？刚开始时我也毫无头绪，但最终还是搬了，在此记录一下我跨省搬家的经过。",-1),c=d('<h1 id="自行车编" tabindex="-1"><a class="header-anchor" href="#自行车编" aria-hidden="true">#</a> 自行车编</h1><p>虽然由于疫情和沙尘暴，我的自行车已经布满沙尘了（并且手柄也热到融化了），但是我还是想把它也搬走。</p><p>首先我用抹布将沙尘拭去，然后去换了个新手柄，这车就和新的一样了（迫真）。</p><p>友人告诉我，学校南门外的自行车店可以帮忙拆车，于是就骑过去将车托付。拆车是需要时间的，他让我先回去等着。等到他通知我车拆完了，我便约了快递去车店去，随后在app上进行邮费的支付，完成自行车的发货。如此自己便不需要再过去了，可谓脱手。</p><h1 id="流体编" tabindex="-1"><a class="header-anchor" href="#流体编" aria-hidden="true">#</a> 流体编</h1><p>好在我的流体并不很多，于是便缠了几圈泡沫纸带在行李箱里肉身运即可。</p><p>值得一提的是，对于沐浴露，可以去洗手台将它的那个喷口拧回去。</p><h1 id="台式机编" tabindex="-1"><a class="header-anchor" href="#台式机编" aria-hidden="true">#</a> 台式机编</h1><p>对于台式机，我咨询了群友的意见，群友给出了如下三种解决方案：</p><ol><li>拆了分开运（对我而言太麻烦了）</li><li>塞行李箱里运（他们指出26寸应该可以装得下，但是得少走人行道）</li><li>用主机包运</li></ol><p>综合考虑，用主机包运应该是最省心的方案了，于是我便买了个主机包，自己带着运了。主机包可以同时塞下显示屏与主机，可谓省心！</p><h1 id="杂物编" tabindex="-1"><a class="header-anchor" href="#杂物编" aria-hidden="true">#</a> 杂物编</h1><p>杂物就是塞在箱子里就好了，手办则塞入手办盒子（没盒的我缠了几圈泡泡纸，看天了），桌游则垫纸绑胶带。如果有珍贵易碎物品，或许还是自己带着运比较好。</p>',13);function s(l,p){return r(),t("div",null,[n,o,i(" more "),c])}const f=a(h,[["render",s],["__file","Move.html.vue"]]);export{f as default};
